function void uvm_phase::add(uvm_phase phase, int with_phase=null, int after_phase=null,
                             uvm_phase before_phase=null, int start_with_phase=null, int end_with_phase=null);
  if (before_phase != null) begin
    foreach (before_phase.m_predecessors[pred]) begin
      pred.m_successors[begin_node] = 1;
    end
  end
endfunction

class uvm_component;
  extern function int get_child(string name);
endclass
function int uvm_component::get_child(string name);
  if (m_children.exists(name))
    return m_children[name];
endfunction
